metadata.sourceCode:
const poll = $context.$nodes.LOOP_STATUS.GET_JOB_STATUS.$output;
const status = String(poll.status || '').toUpperCase();

  if (status === 'COMPLETE') {
   $context.$variables.jobStatus  = false;
    return {
      execute: false,
      status: status,
      output: poll.text || poll.output || '',
      timeout: false,
      error: ''
    };
  }

  if (status === 'ERROR') {
   $context.$variables.jobStatus  = false;
    return {
      execute: false,
      status: status,
      output: '',
      timeout: false,
      error: poll.error || 'pollJobStatus returned ERROR'
    };
  }

  return {
    execute: true,
    status: status || 'UNKNOWN',
    output: '',
    timeout: false,
    error: ''
  };
